import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"69E. Hsrs","description":"","frontmatter":{"title":"69E. Hsrs","eba":"Mental Health Services 2024-2028","topics":["union-matters","ohs"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69E-hsrs.md","filePath":"ebas/mental-health/common-terms/ohs/69E-hsrs.md"}'),a={name:"ebas/mental-health/common-terms/ohs/69E-hsrs.md"};function n(i,e,l,p,h,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_69e-hsrs" tabindex="-1">69E. Hsrs <a class="header-anchor" href="#_69e-hsrs" aria-label="Permalink to &quot;69E. Hsrs&quot;">​</a></h1><p><strong>69E.1</strong> HSR(s) Election Process</p><p><strong>(a)</strong> All Employees in the relevant DWG will be given the opportunity to nominate for a position as an HSR.</p><p><strong>(b)</strong> Where there is more than one nominee for any vacancy of an HSR position, the method of conducting the election will be determined by the Employees of the DWG concerned. The relevant Union will, where requested by the staff, conduct the election.</p><p><strong>(c)</strong> If there is equivalent nominees to positions vacant then the candidate(s) will be elected unopposed.</p><p><strong>(d)</strong> The Employer will maintain a current list of DWGs as well as the name(s) of the elected HSR(s) and vacant positions for each DWG, date(s) of election and date(s) that the HSR(s) undertook HSR training and will display this in a prominent place in the workplace at all times.</p><p><strong>(e)</strong> Employers will provide a copy of the DWG list, with the names of the HSR(s), date(s) of election and date(s) that the HSR(s) undertook HSR training to the relevant union within 28 days of receiving a written request from either the ANMF or HACSU.</p><p><strong>(f)</strong> Immediately following 30 March and 30 September each year, Employers will provide a copy of the DWG list in the format set out below, preferably in Microsoft Excel, with the names of the HSR(s) relevant to Employees as well as other information set out below where practicable: Employer Campus Name of DWG Name of elected HSRs Classification Election date Training Date (5 day and Deputy HSRs course)</p><p>(if no HSR state “vacant” )</p><p>First Name Surname</p><p><strong>69E.2</strong> HSR Training</p><p><strong>(a)</strong> HSRs will be entitled and encouraged to attend a WorkSafe Victoria approved course as soon as practicable following their election.</p><p><strong>(b)</strong> The Employer will permit HSRs to take such time as is necessary or prescribed to attend OHS training courses approved by WorkSafe Victoria.</p><p><strong>(c)</strong> HSRs will have the right to choose which course to attend, provided it is a WorkSafe Victoria approved course. Where the Employer does not agree with the</p><p>selected course the matter will be referred to a Worksafe Inspector in accordance with the OHS Act.</p><p><strong>(d)</strong> When attending an approved course, HSRs will be paid as per their roster, that is the normal/expected earnings during course attendance, including pay entitlements relating to shift work, regular overtime, higher duties, allowances or penalty rates that would have applied had the HSR been at work.</p><p><strong>(e)</strong> Where HSRs attend an approved course outside their normal working hours or roster, they will be paid as if they had been at work for the relevant time, including any relevant overtime rates, higher rates, allowances or penalty rates. This might apply when a</p><p><strong>(f)</strong> HSR:</p><p><strong>(i)</strong> normally works two days a week, and attends a block five-day course</p><p><strong>(ii)</strong> has a rostered day off during the course; and</p><p><strong>(iii)</strong> has a shift that does not overlap, or overlaps only marginally, with the course&#39;s hours.</p><p><strong>(g)</strong> Rosters or shifts prior to/post HSR training will be altered where necessary to ensure that HSRs are not exposed to extra risks from fatigue due to working extended hours or shiftwork while attending a training course.</p><p><strong>(h)</strong> The Employer is responsible for payment of course fees, travel costs and accommodation for HSR attendance at WorkSafe Victoria approved courses.</p><p><strong>69E.3</strong> Facilities for HSRs</p><p><strong>(a)</strong> HSRs will be provided with reasonable access to an office, telephone, computer (including email facilities where available), notice board, meeting room, and such other facilities as are necessary to enable them to perform their functions or duties as prescribed under the OHS Act.</p><p><strong>(b)</strong> HSRs will have reasonable time release from duty to perform their functions and duties as is necessary or prescribed under the OHS Act.</p><p><strong>69E.4</strong> Health and Safety Committees</p><p>Health and safety committees will be established where requested by a HSR.</p>',28)])])}const g=t(a,[["render",n]]);export{m as __pageData,g as default};
